import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const askNexusAI = async (
  userQuery: string, 
  contextData: any
): Promise<string> => {
  try {
    const model = 'gemini-2.5-flash';

    // Prepare a compact context string from the provided data
    const contextString = JSON.stringify(contextData).substring(0, 20000); // Limit context size

    const prompt = `
      You are Nexus AI, an advanced facility and real estate assistant for an enterprise IWMS system.
      You have access to the following JSON data representing the current system state (properties, work orders, etc.):

      DATA CONTEXT:
      ${contextString}

      USER QUERY:
      "${userQuery}"

      INSTRUCTIONS:
      1. Answer the user's question directly based on the data provided.
      2. If analyzing data, provide brief insights (e.g., "The occupancy rate is low at Property X").
      3. Keep the tone professional, concise, and helpful (Enterprise software persona).
      4. Format the output as clean text, using bullet points if listing items.
    `;

    const response = await ai.models.generateContent({
      model: model,
      contents: prompt,
    });

    return response.text || "I was unable to process that request based on the current data.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "I'm currently offline or unable to reach the AI service. Please check your API key configuration.";
  }
};

