const NavItem = ({ icon: Icon, label, path, active, collapsed }: any) => {
  const navigate = useNavigate();
  return (
    <button
      onClick={() => navigate(path)}
      className={`w-full flex items-center gap-3 px-4 py-3 transition-colors duration-200
        ${active ? 'bg-blue-900/50 text-blue-100 border-r-4 border-blue-400' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}
      `}
    >
      <Icon size={20} />
