          <Route path="/financials" element={<Placeholder title="Financials & Cost Centers" />} />
          <Route path="/people" element={<Placeholder title="People & Workplace Services" />} />
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>

        {/* Global AI Drawer */}
        <AiDrawer 
          isOpen={isAiOpen} 
          onClose={() => setIsAiOpen(false)} 
          contextData={appContextData} 
        />
      </Layout>
    </Router>
  );
};

