                 <Bar dataKey="Actual" fill="#4f46e5" radius={[4, 4, 0, 0]} />
               </BarChart>
             </ResponsiveContainer>
          </div>

        </div>
      </div>
    </div>
  );
};

export enum Status {
  Active = 'Active',
  Pending = 'Pending',
  Closed = 'Closed',
  Critical = 'Critical',
  Warning = 'Warning',
  Good = 'Good',
  OnTrack = 'On Track',
  AtRisk = 'At Risk',
  Overdue = 'Overdue'
}

export interface Document {
  id: string;
  name: string;
  type: 'PDF' | 'CAD' | 'Lease Agreement' | 'Invoice' | 'Permit';
  url: string;
  uploadedDate: string;
  size: string;
}

export interface Property {
  id: string;
  name: string;
  address: string;
  type: 'Office' | 'Industrial' | 'Retail' | 'Lab';
  sizeSqFt: number;
  occupancyRate: number;
  status: Status;
  marketValue: number;
  imageUrl: string;
  documents?: Document[];
  noi: number; // Net Operating Income
}

export interface Lease {
  id:string;
  propertyId: string;
  tenantName: string;
  startDate: string;
  endDate: string;
  monthlyRent: number;
  status: 'Active' | 'Expiring Soon' | 'Expired';
  criticalDates: { name: string; date: string }[];
}

export interface Vendor {
  id: string;
  name: string;
  trade: 'HVAC' | 'Plumbing' | 'Electrical' | 'General Contractor' | 'Janitorial';
  rating: number; // 1-5
  onTimeCompletionRate: number; // 0-100
  avgInvoiceCost: number;
}

export interface CostCenter {
  id: string;
  name: string;
  owner: string; // employeeId
  budget: number;
  spent: number;
}

export interface WorkOrder {
  id: string;
  title: string;
  propertyId: string;
  priority: 'Low' | 'Medium' | 'High' | 'Emergency';
  status: 'Open' | 'In Progress' | 'Completed' | 'On Hold';
  category: 'HVAC' | 'Plumbing' | 'Electrical' | 'General' | 'Corrective' | 'Preventive';
  assignedTo: string; // employeeId or vendorId
  dueDate: string;
  cost: number;
  costCenterId: string;
}

export interface InventoryItem {
  id: string;
  name: string;
  sku: string;
  stock: number;
  reorderLevel: number;
  location: string;
}

export interface SafetyIncident {
  id: string;
  propertyId: string;
  type: 'Injury' | 'Property Damage' | 'Near Miss';
  date: string;
  severity: 'Low' | 'Medium' | 'High';
  status: 'Open' | 'Under Investigation' | 'Closed';
}

export interface Asset {
  id: string;
  name: string;
  serialNumber: string;
  purchaseDate: string;
  warrantyEnd: string;
  condition: number; // 0-100
  location: string;
  propertyId: string;
}

export interface PreventiveMaintenanceSchedule {
  id: string;
  assetId: string;
  task: string;
  frequency: 'Weekly' | 'Monthly' | 'Quarterly' | 'Annually';
  nextDueDate: string;
}

export interface SpaceMetric {
  floor: string;
  utilization: number; // 0-100
  department: string;
  seatsTotal: number;
  seatsAvailable: number;
}

export interface Employee {
  id: string;
  name: string;
  title: string;
  department: string;
  email: string;
  location: string; // Assigned desk/office
  phone: string;
  imageUrl: string;
}

export interface ServiceRequest {
  id: string;
  submittedBy: string; // employeeId
  type: 'Temperature' | 'Maintenance' | 'Janitorial' | 'IT';
