const getStatusColor = (status: Status) => {
  switch (status) {
    case Status.OnTrack: return 'bg-green-100 text-green-800';
    case Status.AtRisk: return 'bg-amber-100 text-amber-800';
    case Status.Overdue: return 'bg-red-100 text-red-800';
    case Status.Pending: return 'bg-slate-100 text-slate-800';
    default: return 'bg-slate-100 text-slate-800';
  }
};

const GanttChart = ({ project }: { project: any }) => {
  const tasks = [
    { name: 'Planning & Design', start: 0, end: 20 },
    { name: 'Permitting', start: 15, end: 40 },
    { name: 'Site Prep', start: 40, end: 50 },
    { name: 'Construction', start: 50, end: 95 },
    { name: 'Inspection & Closeout', start: 95, end: 100 },
  ];
  return (
    <div className="space-y-2 mt-4 text-xs">
      {tasks.map(task => (
        <div key={task.name} className="flex items-center">
          <div className="w-40 pr-2 text-slate-600 truncate">{task.name}</div>
          <div className="flex-1 bg-slate-100 rounded-full h-4 relative">
            <div className="absolute bg-blue-500 h-4 rounded-full" style={{ left: `${task.start}%`, width: `${task.end - task.start}%`}}></div>
          </div>
        </div>
      ))}
    </div>
  )
}

